7	------------------------------------------------------------------------------
8	-- Description
9	------------------------------------------------------------------------------
10	-- This entity implements a simple SPI-master.
11	
12	library ieee;
13	use ieee.std_logic_1164.all;
14	use ieee.numeric_std.all;
15	use ieee.math_real.all;
16	
17	use work.psi_common_math_pkg.all;
18	use work.psi_common_logic_pkg.all;
