20	-- @formatter:off
21	entity psi_common_spi_master is
22	  generic(clk_div_g         : natural range 4 to 1_000_000;                      -- Must be a multiple of two
23	          trans_width_g     : positive;                                          -- SPI Transaction width
24	          cs_high_cycles_g  : positive;                                          -- Minimal number of CS high cycle between 2 trans
25	          spi_cpol_g        : natural range 0 to 1;                              -- SPI clock polarity
26	          spi_cpha_g        : natural range 0 to 1;                              -- SPI sampling edge config
27	          slave_cnt_g       : positive  := 1;                                    -- Number if slaves to support
28	          lsb_first_g       : boolean   := false;                                -- False = MSB first trasnmission and True LSB
29	          mosi_idle_state_g : std_logic := '0';                                  -- Idle state of the MOSI line
30	          rst_pol_g         : std_logic:= '1';                                   -- Reset polarity
31	          read_bit_pol_g     : std_logic := '1';                                 -- Polarity of Read operation in RW bit in MOSI word (needed in 3-Wires SPI)
32	          tri_state_pol_g    : std_logic := '1';                                 -- Polarity of tristate signal in case of a 3-Wires SPI
33	          spi_data_pos_g     : positive := 3);                                   -- Starting bit position of Data in MOSI word (needed in 3-Wires SPI)
34	  port(   -- Control Signals                                                    
35	          clk_i      : in  std_logic;                                            -- system clock
36	          rst_i      : in  std_logic;                                            -- system reset (sync)
37	          -- Parallel Interface                                                  
38	          start_i    : in  std_logic;                                            -- a high pulse on this line starts the trasnfer, Note that starting a transaction is  only possible when *Busy* is low.
39	          slave_i    : in  std_logic_vector(log2ceil(slave_cnt_g) - 1 downto 0); --  Slave number to access
40	          busy_o     : out std_logic;                                            -- High during a transaction
41	          done_o     : out std_logic;                                            -- Pulse that goes high for exactly one clock cycle after a transaction is done and *RdData* is valid
42	          dat_i      : in  std_logic_vector(trans_width_g - 1 downto 0);         --  Data to send to  slave. Sampled  during *Start = '1'*
43	          dat_o      : out std_logic_vector(trans_width_g - 1 downto 0);         -- Data received from slave. Must be sampled during *Done = '1'* or *Busy = '0'*.
44	          -- SPI
45	          spi_sck_o  : out std_logic;                                            -- SPI clock
46	          spi_mosi_o : out std_logic;                                            -- SPI master to slave data signal
47	          spi_miso_i : in  std_logic;                                            -- SPI slave to master data signal
48	          spi_tri_o  : out std_logic;                                            -- SPI tri-state buffer select if 3-wires SPI is used
49	          spi_cs_n_o : out std_logic_vector(slave_cnt_g - 1 downto 0);           -- SPI slave select signal (low active)
50	          spi_le_o   : out std_logic_vector(slave_cnt_g - 1 downto 0));          -- SPI slave latch enable (high active)
51	end entity;
52	-- @formatter:on
53	
54	architecture rtl of psi_common_spi_master is
55	
56	  -- *** Types ***
57	  type State_t is (Idle_s, SftComp_s, ClkInact_s, ClkAct_s, CsHigh_s);
58	
59	  -- *** Constants ***
60	  constant ClkDivThres_c : natural := clk_div_g / 2 - 1;
61	  constant BitCntDataPos_c : natural := trans_width_g - spi_data_pos_g;
62	
63	  -- *** Two Process Method ***
64	  type two_process_r is record
65	    State      : State_t;
66	    StateLast  : State_t;
67	    IsRead    : std_logic;
68	    ShiftReg   : std_logic_vector(trans_width_g - 1 downto 0);
69	    dat_o      : std_logic_vector(trans_width_g - 1 downto 0);
70	    spi_cs_n_o : std_logic_vector(slave_cnt_g - 1 downto 0);
71	    spi_le_o   : std_logic_vector(slave_cnt_g - 1 downto 0);
72	    spi_sck_o  : std_logic;
73	    spi_mosi_o : std_logic;
74	    spi_tri_o    : std_logic;
75	    ClkDivCnt  : integer range 0 to ClkDivThres_c;
76	    BitCnt     : integer range 0 to trans_width_g;
77	    CsHighCnt  : integer range 0 to cs_high_cycles_g - 1;
78	    busy_o     : std_logic;
79	    done_o     : std_logic;
80	    MosiNext   : std_logic;
81	  end record;
82	  signal r, r_next : two_process_r;
83	
84	  -- *** Functions and procedures ***
85	  function GetClockLevel(ClkActive : boolean) return std_logic is
86	  begin
87	    if spi_cpol_g = 0 then
88	      if ClkActive then
89	        return '1';
90	      else
91	        return '0';
92	      end if;
93	    else
94	      if ClkActive then
95	        return '0';
96	      else
97	        return '1';
98	      end if;
99	    end if;
100	  end function;
101	
102	  procedure ShiftReg(signal BeforeShift  : in std_logic_vector(trans_width_g-1 downto 0);
103	                     variable AfterShift : out std_logic_vector(trans_width_g-1 downto 0);
104	                     signal InputBit     : in std_logic;
105	                     variable OutputBit  : out std_logic) is
106	  begin
107	    if lsb_first_g then
108	      OutputBit  := BeforeShift(0);
109	      AfterShift := InputBit & BeforeShift(BeforeShift'high downto 1);
110	    else
111	      OutputBit  := BeforeShift(BeforeShift'high);
112	      AfterShift := BeforeShift(BeforeShift'high - 1 downto 0) & InputBit;
113	    end if;
114	  end procedure;
115	
116	begin
117	  --------------------------------------------------------------------------
118	  -- Assertions
119	  --------------------------------------------------------------------------
120	  assert floor(real(clk_div_g) / 2.0) = ceil(real(clk_div_g) / 2.0) report "###ERROR###: psi_common_spi_master - Ratio clk_div_g must be a multiple of two" severity error;
121	
122	  p_comb : process(r, start_i, dat_i, spi_miso_i, slave_i)
123	    variable v : two_process_r;
124	  begin
125	    -- *** hold variables stable ***
126	    v := r;
127	
128	    -- *** Default Values ***
129	    v.done_o := '0';
130	
131	    -- *** State Machine ***
132	    case r.State is
133	      when Idle_s =>
134	        -- Start of Transfer
135	        if start_i = '1' then
136	          v.ShiftReg                                  := dat_i;
137	          v.IsRead                                    := dat_i  (trans_width_g - 1);
138	          v.spi_cs_n_o(to_integer(unsigned(slave_i))) := '0';
139	          v.State                                     := SftComp_s;
140	          v.busy_o                                    := '1';
141	        end if;
142	        v.CsHighCnt := 0;
143	        v.ClkDivCnt := 0;
144	        v.BitCnt    := 0;
145	        v.spi_le_o  := (others => '0');
146	      when SftComp_s =>
147	        v.State := ClkInact_s;
148	        -- Compensate shift for CPHA 0
149	        if spi_cpha_g = 0 then
150	          ShiftReg(r.ShiftReg, v.ShiftReg, spi_miso_i, v.MosiNext);
151	        end if;
152	
153	      when ClkInact_s =>
154	        v.spi_sck_o := GetClockLevel(false);
155	        -- Apply/Latch data if required
156	        if r.ClkDivCnt = 0 then
157	          if spi_cpha_g = 0 then
158	            v.spi_mosi_o := r.MosiNext;
159	            -- Only for 3-Wires SPI
160	            if r.BitCnt = BitCntDataPos_c and r.IsRead = read_bit_pol_g then
161	              v.spi_tri_o := tri_state_pol_g;
162	            end if;
163	          else
164	            ShiftReg(r.ShiftReg, v.ShiftReg, spi_miso_i, v.MosiNext);
165	          end if;
166	        end if;
167	        -- Clock period handling
168	        if r.ClkDivCnt = ClkDivThres_c then
169	          -- All bits done
170	          if r.BitCnt = trans_width_g then
171	            v.spi_mosi_o := mosi_idle_state_g;
172	            v.State      := CsHigh_s;
173	            v.spi_le_o   := not r.spi_cs_n_o;
174	            v.spi_tri_o := not tri_state_pol_g;
175	          -- Otherwise contintue
176	          else
177	            v.State := ClkAct_s;
178	          end if;
179	          v.ClkDivCnt := 0;
180	        else
181	          v.ClkDivCnt := r.ClkDivCnt + 1;
182	        end if;
183	
184	      when ClkAct_s =>
185	        v.spi_sck_o := GetClockLevel(true);
186	        -- Apply data if required
187	        if r.ClkDivCnt = 0 then
188	          if spi_cpha_g = 1 then
189	            v.spi_mosi_o := r.MosiNext;
190	            -- Only for 3-Wires SPI
191	            if r.BitCnt = BitCntDataPos_c and r.IsRead = read_bit_pol_g then
192	              v.spi_tri_o := tri_state_pol_g;
193	            end if;
194	          else
195	            ShiftReg(r.ShiftReg, v.ShiftReg, spi_miso_i, v.MosiNext);
196	          end if;
197	        end if;
198	        -- Clock period handling
199	        if r.ClkDivCnt = ClkDivThres_c then
200	          v.State     := ClkInact_s;
201	          v.ClkDivCnt := 0;
202	          v.BitCnt    := r.BitCnt + 1;
203	        else
204	          v.ClkDivCnt := r.ClkDivCnt + 1;
205	        end if;
206	
207	      when CsHigh_s =>
208	        v.spi_mosi_o := '0';
209	        v.spi_cs_n_o := (others => '1');
210	        v.spi_tri_o  := not tri_state_pol_g;
211	        if r.CsHighCnt = cs_high_cycles_g - 1 then
212	          v.State  := Idle_s;
213	          v.busy_o := '0';
214	          v.done_o := '1';
215	          v.dat_o  := r.ShiftReg;
216	        else
217	          v.CsHighCnt := r.CsHighCnt + 1;
218	        end if;
219	
220	      when others => null;
221	    end case;
222	
223	    -- *** assign signal ***
224	    r_next <= v;
225	  end process;
226	
227	  -- Outputs
228	  busy_o     <= r.busy_o;
229	  done_o     <= r.done_o;
230	  dat_o      <= r.dat_o;
231	  spi_sck_o  <= r.spi_sck_o;
232	  spi_cs_n_o <= r.spi_cs_n_o;
233	  spi_mosi_o <= r.spi_mosi_o;
234	  spi_tri_o  <= r.spi_tri_o;
235	  spi_le_o   <= r.spi_le_o;
236	  p_seq : process(clk_i)
237	  begin
238	    if rising_edge(clk_i) then
239	      r <= r_next;
240	      if rst_i = rst_pol_g then
241	        r.State      <= Idle_s;
242	        r.spi_cs_n_o <= (others => '1');
243	        r.spi_le_o   <= (others => '0');
244	        r.spi_sck_o  <= GetClockLevel(false);
245	        r.busy_o     <= '0';
246	        r.done_o     <= '0';
247	        r.spi_mosi_o <= mosi_idle_state_g;
248	        r.spi_tri_o  <= '0';
249	      end if;
250	    end if;
251	  end process;
252	
253	end architecture;
254	
