7	
8	------------------------------------------------------------------------------
9	-- Description
10	------------------------------------------------------------------------------
11	-- This entity implements a simple SPI-master
12	-- Modification: allows modifying transmit vector length dynamically
13	
14	library ieee;
15	use ieee.std_logic_1164.all;
16	use ieee.numeric_std.all;
17	use ieee.math_real.all;
18	
19	use work.psi_common_math_pkg.all;
