22	-- @formatter:off
23	entity psi_common_spi_master_cfg is
24	  generic(clock_divider_g   : natural range 4 to 1_000_000 := 4;                          -- Must be a multiple of two, Ratio between *clk_i* and the *spi_sck_o* frequency
25	          max_trans_width_g : positive                     := 16;                         -- Maximum SPI Transfer width (bits per transfer)
26	          cs_high_cycles_g  : positive                     := 2;                          -- Minimal number of spi_cs_n_o high cycles between two transfers
27	          spi_cpol_g        : natural range 0 to 1         := 1;                          -- SPI clock polarity 
28	          spi_cpha_g        : natural range 0 to 1         := 1;                          -- SPI sampling edge configuration 
29	          slave_cnt_g       : positive                     := 1;                          -- Number of slaves to support (number of spi_cs_n_o* lines)
30	          lsb_first_g       : boolean                      := false;                      -- False => MSB first transmission, True => LSB first transmission
31	          mosi_idle_state_g : std_logic                    := '0';                        -- Idle state of the MOSI line
32	          rst_pol_g         : std_logic                    := '1');                       -- reset polarity, '1' active high
33	  port(    -- Control Signals
34	          clk_i             : in  std_logic;                                              -- system clock
35	          rst_i             : in  std_logic;                                              -- system reset
36	          -- Parallel Interface
37	          start_i           : in  std_logic;                                              -- starts the transfer. Note that starting a transaction is  only possible when busy_o is low.
38	          slave_i           : in  std_logic_vector(log2ceil(slave_cnt_g) - 1 downto 0);   -- Slave number to access  
39	          busy_o            : out std_logic;                                              -- High during a transaction 
40	          done_o            : out std_logic;                                              -- Goes high for a clock cycle after transaction is done and *rd_dat_o* is valid  
41	          wr_dat_i          : in  std_logic_vector(max_trans_width_g - 1 downto 0);       -- Data to send to slave. Sampled  during start_i = '1'
42	          rd_dat_o          : out std_logic_vector(max_trans_width_g - 1 downto 0);       -- Data received from slave. Must be sampled during done = '1' or busy = '0'.   
43	          trans_width_i     : in  std_logic_vector(log2ceil(max_trans_width_g) downto 0); -- indicate the actual vector length to forward/receive
44	          -- SPI
45	          spi_sck_o         : out std_logic;                                              -- SPI clock  
46	          spi_mosi_o        : out std_logic;                                              -- SPI master to slave data signal 
47	          spi_miso_i        : in  std_logic;                                              -- SPI slave to master data signal  
48	          spi_cs_n_o        : out std_logic_vector(slave_cnt_g - 1 downto 0));            -- SPI slave select signal (low active)
49	end entity;
