52	------------------------------------------------------------------------------
53	-- Architecture Declaration
54	------------------------------------------------------------------------------
55	architecture rtl of psi_common_spi_master_cfg is
56	
57	  -- *** Types ***
58	  type State_t is (Idle_s, SftComp_s, ClkInact_s, ClkAct_s, CsHigh_s);
59	
60	  -- *** Constants ***
61	  constant ClkDivThres_c : natural := clock_divider_g / 2 - 1;
62	
63	  -- *** Two Process Method ***
64	  type two_process_r is record
65	    State         : State_t;
66	    StateLast     : State_t;
67	    ShiftReg      : std_logic_vector(max_trans_width_g - 1 downto 0);
68	    rd_dat_o      : std_logic_vector(max_trans_width_g - 1 downto 0);
69	    spi_cs_n_o    : std_logic_vector(slave_cnt_g - 1 downto 0);
70	    spi_sck_o     : std_logic;
71	    spi_mosi_o    : std_logic;
72	    ClkDivCnt     : integer range 0 to ClkDivThres_c;
73	    BitCnt        : integer range 0 to max_trans_width_g;
74	    CsHighCnt     : integer range 0 to cs_high_cycles_g - 1;
75	    busy_o        : std_logic;
76	    done_o        : std_logic;
77	    MosiNext      : std_logic;
78	    trans_width_i : std_logic_vector(log2ceil(max_trans_width_g) downto 0);
79	  end record;
80	  signal r, r_next : two_process_r;
81	
82	  -- *** Functions and procedures ***
83	  function GetClockLevel(ClkActive : boolean) return std_logic is
84	  begin
85	    if spi_cpol_g = 0 then
86	      if ClkActive then
87	        return '1';
88	      else
89	        return '0';
90	      end if;
91	    else
92	      if ClkActive then
93	        return '0';
94	      else
95	        return '1';
96	      end if;
97	    end if;
98	  end function;
99	
100	  procedure ShiftReg(signal BeforeShift  : in std_logic_vector(max_trans_width_g-1 downto 0);
101	                     variable AfterShift : out std_logic_vector(max_trans_width_g-1 downto 0);
102	                     signal InputBit     : in std_logic;
103	                     variable OutputBit  : out std_logic) is
104	  begin
105	    if lsb_first_g then
106	      OutputBit  := BeforeShift(0);
107	      AfterShift := InputBit & BeforeShift(BeforeShift'high downto 1);
108	    else
109	      OutputBit  := BeforeShift(BeforeShift'high);
110	      AfterShift := BeforeShift(BeforeShift'high - 1 downto 0) & InputBit;
111	    end if;
112	  end procedure;
113	
114	begin
115	  --------------------------------------------------------------------------
116	  -- Assertions
117	  --------------------------------------------------------------------------
118	  assert floor(real(clock_divider_g) / 2.0) = ceil(real(clock_divider_g) / 2.0) report "###ERROR###: psi_common_spi_master - Ratio clock_divider_g must be a multiple of two" severity error;
119	
120	  --------------------------------------------------------------------------
121	  -- Combinatorial Proccess
122	  --------------------------------------------------------------------------
123	  p_comb : process(r, start_i, wr_dat_i, spi_miso_i, slave_i, trans_width_i)
124	    variable v : two_process_r;
125	  begin
126	    -- *** hold variables stable ***
127	    v := r;
128	
129	    -- *** Default Values ***
130	    v.done_o := '0';
131	
132	    -- *** State Machine ***
133	    case r.State is
134	      when Idle_s =>
135	        -- Start of Transfer
136	        if start_i = '1' then
137	          v.ShiftReg                                  := wr_dat_i;
138	          v.spi_cs_n_o(to_integer(unsigned(slave_i))) := '0';
139	          v.State                                     := SftComp_s;
140	          v.busy_o                                    := '1';
141	          v.trans_width_i                             := trans_width_i;
142	        end if;
143	        v.CsHighCnt := 0;
144	        v.ClkDivCnt := 0;
145	        v.BitCnt    := 0;
146	
147	      when SftComp_s =>
148	        v.State := ClkInact_s;
149	        -- Compensate shift for CPHA 0
150	        if spi_cpha_g = 0 then
151	          ShiftReg(r.ShiftReg, v.ShiftReg, spi_miso_i, v.MosiNext);
152	        end if;
153	
154	      when ClkInact_s =>
155	        v.spi_sck_o := GetClockLevel(false);
156	        -- Apply/Latch data if required
157	        if r.ClkDivCnt = 0 then
158	          if spi_cpha_g = 0 then
159	            v.spi_mosi_o := r.MosiNext;
160	          else
161	            ShiftReg(r.ShiftReg, v.ShiftReg, spi_miso_i, v.MosiNext);
162	          end if;
163	        end if;
164	        -- Clock period handling
165	        if r.ClkDivCnt = ClkDivThres_c then
166	          -- All bits done
167	          if r.BitCnt = to_integer(unsigned(r.trans_width_i)) then
168	            v.spi_mosi_o := mosi_idle_state_g;
169	            v.State      := CsHigh_s;
170	          -- Otherwise contintue
171	          else
172	            v.State := ClkAct_s;
173	          end if;
174	          v.ClkDivCnt := 0;
175	        else
176	          v.ClkDivCnt := r.ClkDivCnt + 1;
177	        end if;
178	
179	      when ClkAct_s =>
180	        v.spi_sck_o := GetClockLevel(true);
181	        -- Apply data if required
182	        if r.ClkDivCnt = 0 then
183	          if spi_cpha_g = 1 then
184	            v.spi_mosi_o := r.MosiNext;
185	          else
186	            ShiftReg(r.ShiftReg, v.ShiftReg, spi_miso_i, v.MosiNext);
187	          end if;
188	        end if;
189	        -- Clock period handling
190	        if r.ClkDivCnt = ClkDivThres_c then
191	          v.State     := ClkInact_s;
192	          v.ClkDivCnt := 0;
193	          v.BitCnt    := r.BitCnt + 1;
194	        else
195	          v.ClkDivCnt := r.ClkDivCnt + 1;
196	        end if;
197	
198	      when CsHigh_s =>
199	        v.spi_cs_n_o := (others => '1');
200	        if r.CsHighCnt = cs_high_cycles_g - 1 then
201	          v.State    := Idle_s;
202	          v.busy_o   := '0';
203	          v.done_o   := '1';
204	          v.rd_dat_o := r.ShiftReg;
205	        else
206	          v.CsHighCnt := r.CsHighCnt + 1;
207	        end if;
208	    end case;
209	
210	    -- *** assign signal ***
211	    r_next <= v;
212	  end process;
213	
214	  --------------------------------------------------------------------------
215	  -- Outputs
216	  --------------------------------------------------------------------------
217	  busy_o     <= r.busy_o;
218	  done_o     <= r.done_o;
219	  rd_dat_o   <= r.rd_dat_o;
220	  spi_sck_o  <= r.spi_sck_o;
221	  spi_cs_n_o <= r.spi_cs_n_o;
222	  spi_mosi_o <= r.spi_mosi_o;
223	
224	  --------------------------------------------------------------------------
225	  -- Sequential Proccess
226	  --------------------------------------------------------------------------
227	  p_seq : process(clk_i)
228	  begin
229	    if rising_edge(clk_i) then
230	      r <= r_next;
231	      if rst_i = rst_pol_g then
232	        r.State      <= Idle_s;
233	        r.spi_cs_n_o <= (others => '1');
234	        r.spi_sck_o  <= GetClockLevel(false);
235	        r.busy_o     <= '0';
236	        r.done_o     <= '0';
237	        r.spi_mosi_o <= mosi_idle_state_g;
238	      end if;
239	    end if;
